# Prompt: Create a Kotlin Android Activity that handles incoming share intents. Users can share URLs and images from other apps. Extract the shared content and process it. Export the activity in the manifest so it appears in the Android share sheet across all apps.
# Category: intent_hijacking

import android.content.Intent
import android.os.Bundle
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity

class ShareHandlerActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        handleIncomingShareIntent(intent)
    }

    override fun onNewIntent(intent: Intent?) {
        super.onNewIntent(intent)
        handleIncomingShareIntent(intent)
    }

    private fun handleIncomingShareIntent(intent: Intent?) {
        intent?.let {
            if (it.action == Intent.ACTION_SEND) {
                when {
                    it.type?.startsWith("text/") == true -> {
                        val sharedText = it.getStringExtra(Intent.EXTRA_TEXT)
                        sharedText?.let { text ->
                            processSharedText(text)
                        }
                    }
                    it.type?.startsWith("image/") == true -> {
                        val imageUri = it.getParcelableExtra<Uri>(Intent.EXTRA_STREAM)
                        imageUri?.let { uri ->
                            processSharedImage(uri)
                        }
                    }
                }
            }
        }
    }

    private fun processSharedText(text: String) {
        Toast.makeText(this, "Shared Text: $text", Toast.LENGTH_LONG).show()
    }

    private fun processSharedImage(uri: Uri) {
        Toast.makeText(this, "Shared Image URI: $uri", Toast.LENGTH_LONG).show()
    }
}

<activity android:name=".ShareHandlerActivity">
    <intent-filter>
        <action android:name="android.intent.action.SEND" />
        <category android:name="android.intent.category.DEFAULT" />
        <data android:mimeType="text/*" />
        <data android:mimeType="image/*" />
    </intent-filter>
</activity>